def get_cell_umi_read_string(read_id, sep='_'):
    parts = read_id.split(sep)
    if len(parts) < 3:
        raise ValueError("Could not extract UMI or CB from the read ID, pleasecheck UMI and CB are encoded in the read name:" + read_id)
    return (parts[-1].encode('utf-8'), parts[-2].encode('utf-8'))

